INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (0, "vo_minigame_1013", "", "vo_minigame_1013_top_talk_6_002", "", "", 6015, 0, 6, 21, "");
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (1, 129811, 0, "いやいや何でもない！\nあたしは別に変なこと\n考えてないからな！\nそれより訓練だっ！", 0, 0.3, 6016, 9, 6, 11, 0);
