INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (1, 129911, 0, "私の班のみなさんも\n変わらず訓練に励んで\nいるようですわね\n殊勝なことです", 0, 0.3, 7006, 6, 7, 11, 0);
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES ("", 0, "", "", "", "", 7007, "", 7, 91, "");
