INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (1, 129911, 0, "彼らが私に逆らわずに\n努力したからこそ、\n得たものもありますし\n…感謝しておきますわ", 0, 0.5, 7016, 6, 7, 11, 0);
