INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (1, 129811, 0, "くっ、そう言われると\n悔しいな…！\nならこの行軍訓練で\n逆転してやるぜ！", 0, 0.3, 8016, 7, 8, 11, 0);
